// Robust Extraction Logic (Regex + Schema.org)
const item = $input.item.json;
const html = item.data || '';
const url = $('Webhook').item.json.body.product_url || '';

let title = 'Producto Desconocido';
let description = 'Sin descripción disponible due to scraping protection.';
let price = 'Consultar';
let image = '';

// Check if scraping succeeded
if (html && typeof html === 'string' && html.length > 100) {
    // 1. Regex Extraction (Meta Tags)
    const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
    if (titleMatch) title = titleMatch[1].replace(/\s+/g, ' ').trim();

    const descMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([\s\S]*?)["']/i) ||
                      html.match(/<meta[^>]*content=["']([\s\S]*?)["'][^>]*name=["']description["']/i);
    if (descMatch) description = descMatch[1].replace(/\s+/g, ' ').trim();

    // Price Regex
    const priceMatch = html.match(/["']price["']\s*:\s*["']?([0-9.,]+)["']?/i) || 
                       html.match(/class=["'][^"']*price[^"']*["'][^>]*>([$\£\€]?[0-9.,]+)/i);
    if (priceMatch) price = priceMatch[1];

    // Image Extraction Priority: Schema > OG > Twitter > SRC

    // A. Schema.org JSON-LD (Most Reliable for Shopify)
    if (!image) {
        try {
            const schemaMatches = html.match(/<script type=["']application\/ld\+json["']>([\s\S]*?)<\/script>/gi);
            if (schemaMatches) {
                for (const script of schemaMatches) {
                    const jsonContent = script.replace(/<[^>]+>/g, '').trim();
                    try {
                        const data = JSON.parse(jsonContent);
                        // Direct Image
                        if (data.image) {
                             image = Array.isArray(data.image) ? data.image[0] : (typeof data.image === 'string' ? data.image : data.image.url);
                             if(image) break;
                        }
                        // Graph Structure
                        if (data['@graph']) {
                             const product = data['@graph'].find(i => i['@type'] === 'Product' || i['@type'] === 'ProductGroup');
                             if (product && product.image) {
                                  image = Array.isArray(product.image) ? product.image[0] : (typeof product.image === 'string' ? product.image : product.image.url);
                                  if(image) break;
                             }
                        }
                    } catch(e) {}
                }
            }
        } catch(e) {}
    }

    // B. Open Graph Image
    if (!image) {
        const ogMatch = html.match(/<meta[^>]*property=["']og:image["'][^>]*content=["']([\s\S]*?)["']/i);
        if (ogMatch) image = ogMatch[1];
    }

    // C. Twitter Image
    if (!image) {
        const twMatch = html.match(/<meta[^>]*name=["']twitter:image["'][^>]*content=["']([\s\S]*?)["']/i);
        if (twMatch) image = twMatch[1];
    }

    // D. Shopify specific fallback
    if (!image) {
         const shopifyMatch = html.match(/["']https:\/\/[^"']*cdn.shopify.com[^"']*products[^"']*\.(jpg|png|webp|jpeg)["']/i);
         if (shopifyMatch) image = shopifyMatch[0].replace(/["']/g, '');
    }
}

// Clean up title
if (title.includes('|')) title = title.split('|')[0].trim();
if (title.includes('-')) title = title.split('-')[0].trim();

// Fallback Title
if (title === 'Producto Desconocido') {
    try {
        const slug = url.split('/').pop().split('?')[0];
        title = slug.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
        description = 'Este producto se llama ' + title + '. Genera anuncios basados en este nombre y la URL: ' + url;
    } catch(e) {}
}

// Normalize Image URL (ensure protocol)
if (image && image.startsWith('//')) image = 'https:' + image;

return {
  product_url: url,
  title: title,
  price: price,
  description: description.substring(0, 3000),
  main_image: image
};

const aiItem = $input.item.json;
const aiResponse = aiItem.output || aiItem.text || aiItem.response || '';
let ads = [];

// Try to access previous node data for main_image
const prevData = $('Extract & Normalize').first().json;

if (aiItem.error) {
    ads = [{ type: 'Error', headline: 'Fallo en IA', primary_text: 'El modelo no respondió. Reintenta.', image_prompt: 'N/A' }];
} else {
    if (typeof aiResponse === 'string') {
        try {
            const cleanJson = aiResponse.replace(/^```json/, '').replace(/```$/, '').trim();
            ads = JSON.parse(cleanJson);
        } catch (e) {
            ads = [{ type: 'Error', headline: 'Error Parsing AI', primary_text: aiResponse, image_prompt: 'N/A' }];
        }
    } else if (Array.isArray(aiResponse)) {
        ads = aiResponse;
    } else if (typeof aiResponse === 'object') {
        ads = [aiResponse];
    }
}

return {
    ads: ads,
    product_image: prevData.main_image || '',
    product_title: prevData.title || ''
};
